import React, { useState, useRef, useEffect } from 'react';
import styled, { keyframes } from 'styled-components';
import { 
  Sparkles, 
  Bot, 
  Zap, 
  Code, 
  Database, 
  Cloud, 
  Rocket, 
  ArrowRight,
  Send,
  Loader,
  CheckCircle,
  AlertCircle,
  Download,
  Play,
  Settings,
  MessageSquare,
  Template,
  Palette,
  Layers
} from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';

const fadeInUp = keyframes`
  from { opacity: 0; transform: translateY(30px); }
  to { opacity: 1; transform: translateY(0); }
`;

const Container = styled.div`
  min-height: 100vh;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  overflow-x: hidden;
`;

const Hero = styled.section`
  padding: 60px 20px;
  text-align: center;
  color: white;
  animation: ${fadeInUp} 0.8s ease-out;
`;

const HeroContent = styled.div`
  max-width: 800px;
  margin: 0 auto;
`;

const Title = styled.h1`
  font-size: 3.5rem;
  font-weight: 800;
  margin-bottom: 20px;
  background: linear-gradient(45deg, #fff, #e2e8f0);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  
  @media (max-width: 768px) {
    font-size: 2.5rem;
  }
`;

const Subtitle = styled.p`
  font-size: 1.25rem;
  margin-bottom: 30px;
  opacity: 0.9;
  line-height: 1.6;
`;

const CTAButton = styled.button`
  background: white;
  color: #667eea;
  border: none;
  padding: 16px 32px;
  border-radius: 50px;
  font-size: 18px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s ease;
  box-shadow: 0 10px 30px rgba(0, 0, 0, 0.2);
  display: inline-flex;
  align-items: center;
  gap: 10px;
  
  &:hover {
    transform: translateY(-3px);
    box-shadow: 0 15px 40px rgba(0, 0, 0, 0.3);
  }
`;

const Features = styled.section`
  padding: 80px 20px;
  background: white;
`;

const FeaturesContainer = styled.div`
  max-width: 1200px;
  margin: 0 auto;
`;

const SectionTitle = styled.h2`
  text-align: center;
  font-size: 2.5rem;
  color: #1a202c;
  margin-bottom: 60px;
  font-weight: 700;
`;

const FeatureGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 40px;
`;

const FeatureCard = styled.div`
  background: #f8fafc;
  border-radius: 20px;
  padding: 30px;
  text-align: center;
  transition: all 0.3s ease;
  border: 2px solid transparent;
  
  &:hover {
    transform: translateY(-5px);
    border-color: #667eea;
    box-shadow: 0 15px 40px rgba(102, 126, 234, 0.1);
  }
`;

const FeatureIcon = styled.div`
  width: 80px;
  height: 80px;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  border-radius: 20px;
  display: flex;
  align-items: center;
  justify-content: center;
  margin: 0 auto 20px;
  color: white;
`;

const FeatureTitle = styled.h3`
  font-size: 1.5rem;
  color: #1a202c;
  margin-bottom: 15px;
  font-weight: 600;
`;

const FeatureDescription = styled.p`
  color: #64748b;
  line-height: 1.6;
`;

const Stats = styled.section`
  padding: 60px 20px;
  background: #1a202c;
  color: white;
`;

const StatsGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 40px;
  max-width: 800px;
  margin: 0 auto;
  text-align: center;
`;

const StatCard = styled.div`
  h3 {
    font-size: 3rem;
    font-weight: 800;
    color: #667eea;
    margin-bottom: 10px;
  }
  
  p {
    font-size: 1.125rem;
    opacity: 0.9;
  }
`;

function Builder() {
  const navigate = useNavigate();

  const features = [
    {
      icon: <Bot size={40} />,
      title: "AI-Powered Generation",
      description: "Just tell the AI what you want to build and watch it create complete applications instantly."
    },
    {
      icon: <Code size={40} />,
      title: "Full-Stack Code",
      description: "Complete React frontend, FastAPI backend, and MySQL database - all generated automatically."
    },
    {
      icon: <Zap size={40} />,
      title: "Lightning Fast",
      description: "Generate production-ready applications in 2-5 minutes instead of weeks or months."
    },
    {
      icon: <Database size={40} />,
      title: "Smart Integrations",
      description: "Automatic integration with Stripe, OpenAI, Google APIs, and more external services."
    },
    {
      icon: <Cloud size={40} />,
      title: "One-Click Deploy",
      description: "Deploy to Docker, Vercel, AWS, or any cloud platform with automatically generated configs."
    },
    {
      icon: <Rocket size={40} />,
      title: "Production Ready",
      description: "Generated code follows best practices with proper authentication and security."
    }
  ];

  return (
    <Container>
      <Hero>
        <HeroContent>
          <Title>
            AI App Builder
            <Sparkles size={40} style={{ marginLeft: '10px', verticalAlign: 'middle' }} />
          </Title>
          <Subtitle>
            Transform your ideas into complete, production-ready applications using natural language.
            <br />
            <strong>Build unlimited projects with no restrictions.</strong>
          </Subtitle>
          <CTAButton onClick={() => navigate('/builder')}>
            Start Building Now
            <ArrowRight size={20} />
          </CTAButton>
        </HeroContent>
      </Hero>

      <Features>
        <FeaturesContainer>
          <SectionTitle>🚀 Build Anything You Can Imagine</SectionTitle>
          <FeatureGrid>
            {features.map((feature, index) => (
              <FeatureCard key={index}>
                <FeatureIcon>
                  {feature.icon}
                </FeatureIcon>
                <FeatureTitle>{feature.title}</FeatureTitle>
                <FeatureDescription>{feature.description}</FeatureDescription>
              </FeatureCard>
            ))}
          </FeatureGrid>
        </FeaturesContainer>
      </Features>

      <Stats>
        <FeaturesContainer>
          <SectionTitle style={{ color: 'white', marginBottom: '40px' }}>
            🎯 Powerful Results
          </SectionTitle>
          <StatsGrid>
            <StatCard>
              <h3>∞</h3>
              <p>Unlimited Projects</p>
            </StatCard>
            <StatCard>
              <h3>2-5</h3>
              <p>Minutes to Build</p>
            </StatCard>
            <StatCard>
              <h3>100%</h3>
              <p>Production Ready</p>
            </StatCard>
            <StatCard>
              <h3>0$</h3>
              <p>No Pricing Limits</p>
            </StatCard>
          </StatsGrid>
        </FeaturesContainer>
      </Stats>
    </Container>
  );
}

export default Builder;
